import React, { useState, useEffect } from "react";
import Logo from "./Logo";
import LoginForm from "./LoginForm";
import RegisterForm from "./RegisterForm";

export default function App() {
  const [screen, setScreen] = useState("logo"); // logo | login | register

  // Tự động chuyển logo → login sau 2s
  useEffect(() => {
    if (screen === "logo") {
      const timer = setTimeout(() => setScreen("login"), 2000);
      return () => clearTimeout(timer);
    }
  }, [screen]);

  return (
    <div>
      {screen === "logo" && <Logo />}
      {screen === "login" && (
        <LoginForm
          goToRegister={() => setScreen("register")} // bạn cần thêm prop này trong LoginForm
        />
      )}
      {screen === "register" && (
        <RegisterForm
          goToLogin={() => setScreen("login")} // bạn cần thêm prop này trong RegisterForm
        />
      )}
    </div>
  );
}
